import regression from 'https://cdn.jsdelivr.net/npm/regression@2/+esm';   // default 导出方法对象
const kind = data.kind ?? 'linear';
const result = regression[kind](data.points, { order: data.order ?? 2, precision: data.precision ?? 2 });
// result.equation 系数 · result.string 方程串 · result.r2 拟合优度 · result.points 拟合点[x,y][]
const curve = result.points;                        // 或对更密 x 采样:xs.map(x => result.predict(x)) —— predict(x) 返回 [x,y] 数对
